import os
import sys

# Add the testbed to path
sys.path.insert(0, os.path.dirname(__file__))

# Import just the Q class without full Django setup
from django.db.models.query_utils import Q

# Create a mock Exists class that behaves like the real one
class MockExists:
    conditional = True

    def __and__(self, other):
        if getattr(self, 'conditional', False) and getattr(other, 'conditional', False):
            return Q(self) & Q(other)
        raise NotImplementedError("Use .bitand() and .bitor() for bitwise logical operations.")

    def __or__(self, other):
        if getattr(self, 'conditional', False) and getattr(other, 'conditional', False):
            return Q(self) | Q(other)
        raise NotImplementedError("Use .bitand() and .bitor() for bitwise logical operations.")

# Test the issue
print('Testing MockExists() & Q()...')
try:
    result = MockExists() & Q()
    print('  Success:', result)
except Exception as e:
    print('  Failed:', type(e).__name__, '-', e)

print('\nTesting Q() & MockExists()...')
try:
    result = Q() & MockExists()
    print('  Success:', result)
except Exception as e:
    print('  Failed:', type(e).__name__, '-', e)

print('\nTesting MockExists() | Q()...')
try:
    result = MockExists() | Q()
    print('  Success:', result)
except Exception as e:
    print('  Failed:', type(e).__name__, '-', e)

print('\nTesting Q() | MockExists()...')
try:
    result = Q() | MockExists()
    print('  Success:', result)
except Exception as e:
    print('  Failed:', type(e).__name__, '-', e)

